export const dynamic = "force-dynamic";

export const metadata: Metadata = {
  title: "ロト6 当選番号一覧",
  description:
    "ロト6の過去の抽選結果（本数字・ボーナス・等級別口数・払戻金・キャリーオーバー）を一覧表示します。",
  alternates: { canonical: "/loto6/result" },
  openGraph: {
    title: "ロト6 当選番号一覧 | 宝くじAI",
    description: "過去の抽選結果を一覧で確認できます。",
    url: "/loto6/result",
  },
};

type PageProps = {
  searchParams: Promise<{ page?: string }>;
};

function parsePage(raw: string | undefined): number {
  const n = parseInt(raw ?? "1", 10);
  if (!Number.isFinite(n) || n < 1) return 1;
  return n;
}

export default async function Loto6ResultPage({ searchParams }: PageProps) {
  const { page: pageParam } = await searchParams;
  const requestedPage = parsePage(pageParam);

  const supabase = await createClient();
  const { count, error: countError } = await supabase
    .from("loto6_draws")
    .select("*", { count: "exact", head: true });

  if (countError) {
    throw new Error(countError.message);
  }

  const totalCount = count ?? 0;
  const totalPages = Math.max(1, Math.ceil(totalCount / LOTO6_PAGE_SIZE));

  if (requestedPage > totalPages && totalCount > 0) {
    redirect(`/loto6/result?page=${totalPages}`);
  }

  const page = Math.min(requestedPage, totalPages);
  const from = (page - 1) * LOTO6_PAGE_SIZE;
  const to = from + LOTO6_PAGE_SIZE - 1;

  const { data, error } = await supabase
    .from("loto6_draws")
    .select("*")
    .order("draw_number", { ascending: false })
    .range(from, to);

  if (error) {
    throw new Error(error.message);
  }

  const rows = (data ?? []) as Loto6DrawRow[];

  const origin = getSiteOrigin();
  const breadcrumbJsonLd = buildBreadcrumbJsonLd([
    { name: "ロト6", path: "/loto6" },
    { name: "当選番号一覧", path: "/loto6/result" },
  ]);

  const datasetJsonLd = {
    "@context": "https://schema.org",
    "@type": "Dataset",
    name: "ロト6 当選番号データセット",
    alternateName: "Loto6 Draw Results Dataset",
    description:
      "日本のロト6の過去の抽選結果（本数字・ボーナス・等級別口数・払戻金）を収録したデータセット。公開データから取得。",
    url: `${origin}/loto6/result`,
    distribution: [
      {
        "@type": "DataDownload",
        encodingFormat: "application/json",
        contentUrl: `${origin}/api/loto6/latest`,
      },
    ],
    keywords: ["Loto6", "ロト6", "lottery", "宝くじ", "当選番号", "Japan"],
  };

  return (
    <div className="flex flex-1 flex-col">
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbJsonLd) }}
      />
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(datasetJsonLd) }}
      />
      <div className="mx-auto w-full max-w-[1600px] flex-1 space-y-8 px-4 py-8 sm:space-y-10 sm:px-6 sm:py-10">
        <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10">
          <CardHeader className="border-border/60 space-y-4 border-b pb-6 sm:pb-6">
            <div className="space-y-2">
              <Badge
                variant="secondary"
                className="border-amber-500/30 bg-amber-500/10 text-amber-900 dark:border-amber-400/30 dark:bg-amber-400/10 dark:text-amber-100"
              >
                Loto6
              </Badge>
              <CardTitle className="font-heading text-xl sm:text-2xl">
                当選番号一覧
              </CardTitle>
              <CardDescription className="text-pretty max-w-2xl text-sm leading-relaxed sm:text-base">
                回号の新しい順に表示しています。狭い画面では表を横にスクロールできます。ページは
                URL の{" "}
                <code className="bg-muted rounded-md px-1.5 py-0.5 font-mono text-xs">
                  page
                </code>{" "}
                でも切り替わります。
              </CardDescription>
            </div>
          </CardHeader>
          <CardContent className="px-0 pb-0">
            <div className="bg-muted/40 border-border/60 border-b px-4 py-3 sm:px-6">
              <Loto6Pagination totalCount={totalCount} currentPage={page} />
            </div>
            <Loto6DrawsTable rows={rows} />
            <div className="bg-muted/40 border-border/60 rounded-b-xl border-t px-4 py-3 sm:px-6">
              <Loto6Pagination totalCount={totalCount} currentPage={page} />
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import type { Metadata } from "next";
import Link from "next/link";
import { notFound } from "next/navigation";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { buttonVariants } from "@/components/ui/button-variants";
import { createClient } from "@/lib/supabase/server";
import { formatYen } from "@/lib/numbers4";
import {
  type Loto6DrawRow,
  formatLoto6NumbersCell,
} from "@/lib/loto6";
import { cn } from "@/lib/utils";

export const dynamic = "force-dynamic";

const TIER_LABELS = [
  { tier: 1 as const, label: "1等" },
  { tier: 2 as const, label: "2等" },
  { tier: 3 as const, label: "3等" },
  { tier: 4 as const, label: "4等" },
  { tier: 5 as const, label: "5等" },
];

function tierKeys(tier: 1 | 2 | 3 | 4 | 5) {
  const w = `tier${tier}_winners` as const;
  const y = `tier${tier}_payout_yen` as const;
  return { w, y };
}

type PageProps = {
  params: Promise<{ draw_number: string }>;
};

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { draw_number } = await params;
  const n = parseInt(draw_number, 10);
  if (!Number.isFinite(n)) return { title: "ロト6" };
  return {
    title: `第${n}回 ロト6 当選結果`,
    alternates: { canonical: `/loto6/result/${n}` },
  };
}

export default async function Loto6ResultDetailPage({ params }: PageProps) {
  const { draw_number } = await params;
  const n = parseInt(draw_number, 10);
  if (!Number.isFinite(n)) notFound();

  const supabase = await createClient();
  const { data: row, error } = await supabase
    .from("loto6_draws")
    .select("*")
    .eq("draw_number", n)
    .maybeSingle();

  if (error) throw new Error(error.message);
  if (!row) notFound();

  const r = row as Loto6DrawRow;

  return (
    <div className="mx-auto w-full max-w-3xl space-y-6 px-4 py-8 sm:px-6 sm:py-10">
      <Link
        href="/loto6/result"
        className={cn(
          buttonVariants({ variant: "ghost", size: "sm" }),
          "text-muted-foreground -ml-2 hover:text-foreground",
        )}
      >
        ← 一覧へ
      </Link>

      <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10">
        <CardHeader>
          <CardTitle className="text-xl">第 {r.draw_number} 回 ロト6</CardTitle>
          <CardDescription>抽選日: {r.draw_date}</CardDescription>
        </CardHeader>
        <CardContent className="space-y-8">
          <div>
            <p className="text-muted-foreground text-sm">本数字</p>
            <p className="font-mono text-2xl font-bold tracking-wide sm:text-3xl">
              {formatLoto6NumbersCell(r.numbers)}
            </p>
            <p className="text-muted-foreground mt-3 text-sm">ボーナス数字</p>
            <p className="text-foreground font-mono text-3xl font-bold sm:text-4xl">
              {r.bonus_number}
            </p>
          </div>

          <div className="space-y-2">
            <p className="text-foreground text-sm font-medium">等級別 当せん口数・払戻金</p>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-[30%]">等級</TableHead>
                  <TableHead className="text-right">当選口数</TableHead>
                  <TableHead className="text-right">払戻金（円）</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {TIER_LABELS.map(({ tier, label }) => {
                  const { w, y } = tierKeys(tier);
                  const wc = r[w];
                  const yc = r[y];
                  return (
                    <TableRow key={tier}>
                      <TableCell className="text-muted-foreground text-sm">
                        {label}
                      </TableCell>
                      <TableCell className="text-right font-mono text-sm tabular-nums">
                        {wc === null || wc === undefined ? "—" : String(wc)}
                      </TableCell>
                      <TableCell className="text-right font-mono text-sm tabular-nums">
                        {formatYen(yc as number | string | null)}
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </div>

          <div>
            <p className="text-muted-foreground text-sm">キャリーオーバー</p>
            <p className="font-mono text-lg font-semibold tabular-nums">
              {formatYen(r.carryover_yen as number | string | null)}
            </p>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { redirect } from "next/navigation";

type PageProps = {
  params: Promise<{ draw_number: string }>;
};

/** 旧 URL `/loto6/{回号}` から当選結果ページへ誘導します。 */
export default async function LegacyLoto6DrawRedirect({ params }: PageProps) {
  const { draw_number } = await params;
  redirect(`/loto6/result/${draw_number}`);
}

import { NextResponse } from "next/server";

import { resolvePublicSupabaseConfig } from "@/lib/env";
import { createClient } from "@/lib/supabase/server";
import { getSiteOrigin } from "@/lib/site";

export const dynamic = "force-dynamic";

export async function GET() {
  const origin = getSiteOrigin();

  let hasSupabase = false;
  try {
    hasSupabase = resolvePublicSupabaseConfig() !== null;
  } catch {
    // no supabase
  }

  if (!hasSupabase) {
    return NextResponse.json(
      {
        error: "Draw data service unavailable",
        site: origin,
        docs: `${origin}/llms.txt`,
      },
      { status: 503 },
    );
  }

  try {
    const supabase = await createClient();
    const { data: draws, error: drawsError } = await supabase
      .from("loto6_draws")
      .select("*")
      .order("draw_number", { ascending: false })
      .limit(10);

    if (drawsError) {
      return NextResponse.json({ error: drawsError.message }, { status: 500 });
    }

    return NextResponse.json(
      {
        site: "Takarakuji AI (宝くじAI)",
        description:
          "Unofficial Loto6 (Japan) draw results. Not affiliated with any lottery operator.",
        disclaimer:
          "Data is for research and entertainment only. Not financial or gambling advice. Verify with official sources.",
        origin,
        latest_draws: draws ?? [],
        links: {
          home: origin,
          hub: `${origin}/loto6`,
