/** predictions/daily/loto6_*.json / methods/*/loto6_*.json と整合する緩い型 */

export type Loto6TopPrediction = {
  rank?: number;
  main?: number[];
  bonus?: number | null;
  score?: number | null;
};

export type Loto6MethodRun = {
  time?: string;
  time_jst?: string;
  method?: string;
  top_predictions?: Loto6TopPrediction[];
};

export type Loto6MethodPayload = {
  draw_number?: number;
  target_draw_number?: number;
  date?: string;
  method?: string;
  predictions?: Loto6MethodRun[];
  prediction_count?: number;
};

export type Loto6EnsembleRun = {
  time?: string;
  time_jst?: string;
  ensemble_weights?: Record<string, number>;
  top_predictions?: Loto6TopPrediction[];
};

export type Loto6EnsemblePayload = {
  draw_number?: number;
  target_draw_number?: number;
  date?: string;
  predictions?: Loto6EnsembleRun[];
  last_updated?: string;
};

export type Loto6MethodRow = {
  slug: string;
  relativePath: string | null;
  payload: Loto6MethodPayload;
};

export type Loto6PredictionBundle = {
  targetDrawNumber: number;
  ensemble: Loto6EnsemblePayload | null;
  methodRows: Loto6MethodRow[];
};

/** 本数字（6球）の一致数。ボーナスは別判定 */

export function parseLoto6MainNumbers(numbers: string | null | undefined): number[] {
  if (!numbers) return [];
  return numbers
    .split(",")
    .map((s) => parseInt(s.trim(), 10))
    .filter((n) => Number.isFinite(n) && n >= 1 && n <= 43);
}

export function countLoto6MainHits(predMain: number[], actualMain: number[]): number {
  const a = new Set(actualMain);
  return predMain.filter((x) => a.has(x)).length;
}

export function isLoto6BonusHit(
  predBonus: number | null | undefined,
  actualBonus: number | null | undefined,
): boolean {
  if (predBonus == null || actualBonus == null) return false;
  return predBonus === actualBonus;
}

import { cache } from "react";

import { createClient } from "@/lib/supabase/server";

import type {
  Loto6EnsemblePayload,
  Loto6MethodPayload,
  Loto6MethodRow,
  Loto6PredictionBundle,
} from "./types";

type DbDocRow = {
  doc_kind: string;
  method_slug: string | null;
  payload: unknown;
  relative_path: string | null;
};

function normalizeMethodRows(rows: Loto6MethodRow[]): Loto6MethodRow[] {
  return [...rows].sort((a, b) => a.slug.localeCompare(b.slug));
}

/**
 * 指定回を予測対象とした JSON バンドル（ensemble + method）を Supabase から読む。
 */
export const loadLoto6PredictionBundle = cache(
  async (targetDrawNumber: number): Promise<Loto6PredictionBundle | null> => {
    if (!Number.isFinite(targetDrawNumber) || targetDrawNumber < 1) return null;

    const supabase = await createClient();
    const { data: rows, error } = await supabase
      .from("loto6_daily_prediction_documents")
      .select("doc_kind, method_slug, payload, relative_path")
      .eq("target_draw_number", targetDrawNumber);

    if (error || !rows?.length) return null;

    let ensemble: Loto6EnsemblePayload | null = null;
    const methodRows: Loto6MethodRow[] = [];

    for (const row of rows as DbDocRow[]) {
      if (row.doc_kind === "ensemble") {
        ensemble = row.payload as Loto6EnsemblePayload;
      } else if (row.doc_kind === "method" && row.method_slug) {
        methodRows.push({
          slug: row.method_slug,
          relativePath: row.relative_path,
          payload: row.payload as Loto6MethodPayload,
        });
      }
    }

    return {
      targetDrawNumber,
      ensemble,
      methodRows: normalizeMethodRows(methodRows),
    };
  },
);

/** DB 上の最新取込回の「次の回号」（予測の表示ターゲット） */
export async function resolveNextLoto6TargetDrawNumber(): Promise<number | null> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from("loto6_draws")
    .select("draw_number")
    .order("draw_number", { ascending: false })
    .limit(1)
    .maybeSingle();

  if (error || data?.draw_number == null) return null;
  const n = data.draw_number;
  return typeof n === "number" && n > 0 ? n + 1 : null;
}

export function lastLoto6MethodRun(
  payload: Loto6MethodPayload | Loto6EnsemblePayload,
): { top_predictions?: import("./types").Loto6TopPrediction[] } | null {
  const preds =
    "method" in (payload as Loto6MethodPayload) ||
    (payload as Loto6MethodPayload).method != null
      ? (payload as Loto6MethodPayload).predictions
      : (payload as Loto6EnsemblePayload).predictions;
  if (!preds?.length) return null;
  return preds[preds.length - 1] ?? null;
}

